document.addEventListener(`DOMContentLoaded`,()=>{let e=document.createElement(`div`);e.setAttribute(`style`,`padding: 4px; display: flex; flex-direction: row; gap: 4px; flex-wrap: wrap`),document.body.appendChild(e);for(let t=0;t<1e4;t++){let n=document.createElement(`div`);n.setAttribute(`style`,`display: inline-block; background-color: black; color: white; border-radius: 4px; padding: 4px; width: ${t+32}px`),n.textContent=t,e.appendChild(n)}});